-- SEED: cursos e módulos (idempotente — pode rodar de novo pra atualizar conteúdo)

insert into public.cursos (id, ordem, nome, sub, etiqueta, cor, cor_suave, curriculo)
values ('matematica', 1, $s$Matemática$s$, $s$Licenciatura Mackenzie EAD · 20 disciplinas · 8 etapas$s$, $s$o curso inteiro$s$, '#2B4C8C', '#F0F4FF', $j$[{"etapa":"Etapa 1","disciplinas":[{"id":"mat-elementar","nome":"Tópicos de Matemática Elementar","ch":4,"ativo":true,"nota":"Nivelamento — começamos por aqui"},{"id":"geo-espacial","nome":"Geometria Espacial","ch":2},{"id":"ed-financeira","nome":"Educação Financeira","ch":2}]},{"etapa":"Etapa 2","disciplinas":[{"id":"geo-analitica","nome":"Geometria Analítica e Vetores","ch":3},{"id":"logica","nome":"Lógica Matemática","ch":2}]},{"etapa":"Etapa 3","disciplinas":[{"id":"calc-dif","nome":"Cálculo Diferencial","ch":4},{"id":"alg-linear","nome":"Álgebra Linear","ch":4}]},{"etapa":"Etapa 4","disciplinas":[{"id":"calc-int","nome":"Cálculo Integral","ch":4},{"id":"pens-comp","nome":"Pensamento Computacional e Programação","ch":3}]},{"etapa":"Etapa 5","disciplinas":[{"id":"calc-varias","nome":"Cálculo de Várias Variáveis","ch":4},{"id":"teoria-numeros","nome":"Teoria dos Números","ch":3}]},{"etapa":"Etapa 6","disciplinas":[{"id":"estr-algebricas","nome":"Estruturas Algébricas","ch":4},{"id":"seq-series","nome":"Sequências e Séries","ch":2},{"id":"geo-axiomatica","nome":"Geometria Axiomática e Desenho Geométrico","ch":4},{"id":"calc-numerico","nome":"Cálculo Numérico e Pesquisa Operacional","ch":4}]},{"etapa":"Etapa 7","disciplinas":[{"id":"edo","nome":"Equações Diferenciais","ch":3},{"id":"trig-complexos","nome":"Trigonometria e Números Complexos","ch":4},{"id":"estatistica","nome":"Estatística Descritiva","ch":2}]},{"etapa":"Etapa 8","disciplinas":[{"id":"probabilidade","nome":"Probabilidade","ch":3},{"id":"analise","nome":"Análise Matemática","ch":4}]}]$j$::jsonb)
on conflict (id) do update set ordem = excluded.ordem, nome = excluded.nome, sub = excluded.sub, etiqueta = excluded.etiqueta, cor = excluded.cor, cor_suave = excluded.cor_suave, curriculo = excluded.curriculo;

insert into public.modulos (id, curso_id, dados)
values ('mat-elementar', 'matematica', $j${"descricao":"A base de tudo que vem depois: conjuntos, funções, exponenciais, logaritmos e progressões. Equivale ao vol. 1 e 2 do Iezzi. ~72h de estudo (4h/semana × 18 semanas).","livros":["Fundamentos de Matemática Elementar, vol. 1 (Conjuntos e Funções) — Gelson Iezzi & Carlos Murakami","Fundamentos de Matemática Elementar, vol. 2 (Logaritmos) — Gelson Iezzi","A Matemática do Ensino Médio, vol. 1 — Elon Lages Lima (SBM). Mais rigoroso; ótimo pra quem quer profundidade","Khan Academy (gratuito) como apoio em vídeo para qualquer tópico"],"aulas":[{"id":"conjuntos","titulo":"1. Conjuntos e conjuntos numéricos","semanas":"Semanas 1–2","teoria":["Um conjunto é uma coleção de objetos (elementos). Notação: A = {1, 2, 3}. Dizemos x ∈ A (pertence) ou x ∉ A. Um conjunto B é subconjunto de A (B ⊂ A) quando todo elemento de B está em A.","Operações: união A ∪ B (elementos em A ou B), interseção A ∩ B (em ambos), diferença A − B (em A mas não em B) e complementar. Vale a fórmula da contagem: n(A ∪ B) = n(A) + n(B) − n(A ∩ B).","Conjuntos numéricos: ℕ = {0,1,2,...} (naturais), ℤ (inteiros, inclui negativos), ℚ (racionais — frações p/q com q ≠ 0, incluem decimais exatos e dízimas periódicas), 𝕀 (irracionais, como √2 e π) e ℝ = ℚ ∪ 𝕀 (reais). Vale ℕ ⊂ ℤ ⊂ ℚ ⊂ ℝ.","Intervalos reais: [a, b] fechado (inclui extremos), (a, b) aberto, [a, b) misto. São a linguagem padrão pra domínio e imagem de funções — apareceremos neles o curso inteiro."],"exemplos":[{"t":"Contagem com dois conjuntos","c":"Numa turma, 20 alunos gostam de Cálculo, 15 de Álgebra e 8 gostam dos dois. Quantos gostam de pelo menos um? n(C ∪ A) = 20 + 15 − 8 = 27."},{"t":"Dízima periódica é racional","c":"x = 0,444... → 10x = 4,444... → 10x − x = 4 → 9x = 4 → x = 4/9. Toda dízima periódica vira fração (por isso é racional)."}],"exercicios":[{"q":"Dados A = {1,2,3,4} e B = {3,4,5}, determine A ∪ B, A ∩ B e A − B.","a":"A ∪ B = {1,2,3,4,5}; A ∩ B = {3,4}; A − B = {1,2}."},{"q":"Numa pesquisa, 120 pessoas usam Azure, 80 usam AWS e 45 usam ambos. Quantas usam pelo menos uma nuvem?","a":"120 + 80 − 45 = 155 pessoas."},{"q":"Escreva 0,272727... como fração irredutível.","a":"x = 0,2727..., 100x = 27,2727..., 99x = 27, x = 27/99 = 3/11."},{"q":"Classifique como racional ou irracional: (a) √9 (b) √8 (c) 0,101001000... (padrão sem período) (d) 22/7","a":"(a) √9 = 3, racional. (b) √8 = 2√2, irracional. (c) irracional (não periódico). (d) racional (é fração)."},{"q":"Verdadeiro ou falso: (a) ℤ ⊂ ℚ (b) todo irracional é real (c) ℚ ∩ 𝕀 = ∅","a":"(a) V — todo inteiro n é a fração n/1. (b) V. (c) V — um número não pode ser racional e irracional ao mesmo tempo."},{"q":"Represente como intervalo: o conjunto dos reais x tais que −2 < x ≤ 5.","a":"(−2, 5]."},{"q":"Se A = [1, 6) e B = (3, 8], determine A ∩ B e A ∪ B.","a":"A ∩ B = (3, 6); A ∪ B = [1, 8]."},{"q":"Num grupo de 60 devs, 32 sabem Python, 25 sabem Java e 10 não sabem nenhuma das duas. Quantos sabem ambas?","a":"Sabem pelo menos uma: 60 − 10 = 50. Então 32 + 25 − x = 50 → x = 7."}]},{"id":"potencias","titulo":"2. Potenciação, radiciação e fatoração","semanas":"Semanas 3–4","teoria":["Propriedades de potências: aᵐ·aⁿ = aᵐ⁺ⁿ; aᵐ/aⁿ = aᵐ⁻ⁿ; (aᵐ)ⁿ = aᵐⁿ; (ab)ⁿ = aⁿbⁿ; a⁰ = 1 (a ≠ 0); a⁻ⁿ = 1/aⁿ. Expoente fracionário: a^(m/n) = ⁿ√(aᵐ).","Radicais: √(ab) = √a·√b (para a, b ≥ 0). Simplificação: √50 = √(25·2) = 5√2. Racionalização: 1/√2 = √2/2 (multiplica em cima e embaixo pelo radical).","Produtos notáveis: (a+b)² = a² + 2ab + b²; (a−b)² = a² − 2ab + b²; (a+b)(a−b) = a² − b². Cubos: (a+b)³ = a³ + 3a²b + 3ab² + b³.","Fatoração — o caminho inverso, essencial pra resolver equações e simplificar expressões: fator comum (ax + ay = a(x+y)), agrupamento, diferença de quadrados (a² − b² = (a+b)(a−b)), trinômio quadrado perfeito, e soma/diferença de cubos: a³ ± b³ = (a ± b)(a² ∓ ab + b²)."],"exemplos":[{"t":"Simplificação com propriedades","c":"(2³ · 2⁵)/2⁶ = 2^(3+5−6) = 2² = 4."},{"t":"Fatoração para simplificar","c":"(x² − 9)/(x + 3) = (x+3)(x−3)/(x+3) = x − 3, para x ≠ −3."},{"t":"Racionalização com conjugado","c":"1/(√5 − √3) = (√5 + √3)/((√5)² − (√3)²) = (√5 + √3)/2."}],"exercicios":[{"q":"Calcule: (a) 2⁻³ (b) 16^(3/4) (c) (5²)³/5⁴","a":"(a) 1/8. (b) (2⁴)^(3/4) = 2³ = 8. (c) 5⁶/5⁴ = 5² = 25."},{"q":"Simplifique √72 + √32 − √8.","a":"6√2 + 4√2 − 2√2 = 8√2."},{"q":"Racionalize: 3/√6.","a":"3√6/6 = √6/2."},{"q":"Desenvolva: (2x − 3)².","a":"4x² − 12x + 9."},{"q":"Fatore: (a) x² − 25 (b) x² + 10x + 25 (c) x³ − 8","a":"(a) (x+5)(x−5). (b) (x+5)². (c) (x−2)(x²+2x+4)."},{"q":"Simplifique (x² + 6x + 9)/(x² − 9).","a":"(x+3)²/((x+3)(x−3)) = (x+3)/(x−3), x ≠ ±3."},{"q":"Se a + b = 7 e ab = 10, calcule a² + b².","a":"a² + b² = (a+b)² − 2ab = 49 − 20 = 29."},{"q":"Racionalize: 2/(√7 + √5).","a":"2(√7 − √5)/(7 − 5) = √7 − √5."}]},{"id":"equacoes","titulo":"3. Equações e inequações","semanas":"Semanas 5–7","teoria":["Equação do 1º grau: ax + b = 0 → x = −b/a. Simples, mas a habilidade de isolar variáveis com segurança é usada em TODO o resto do curso.","Equação do 2º grau: ax² + bx + c = 0. Bhaskara: x = (−b ± √Δ)/2a, com Δ = b² − 4ac. Δ > 0: duas raízes reais; Δ = 0: uma raiz dupla; Δ < 0: nenhuma raiz real. Soma das raízes = −b/a, produto = c/a (relações de Girard — ótimas pra conferir resultado).","Inequações do 1º grau: resolve como equação, mas ao multiplicar/dividir por número negativo, INVERTE o sinal da desigualdade.","Inequação do 2º grau: estude o sinal da parábola. Se a > 0, a parábola é positiva fora das raízes e negativa entre elas. Sempre desenhe um esboço rápido do sinal.","Equações modulares: |x| = a (a ≥ 0) → x = a ou x = −a. |x| < a → −a < x < a. |x| > a → x < −a ou x > a."],"exemplos":[{"t":"Segundo grau completo","c":"x² − 5x + 6 = 0. Δ = 25 − 24 = 1. x = (5 ± 1)/2 → x = 3 ou x = 2. Confere: soma 5 = −(−5)/1 ✓, produto 6 = 6/1 ✓."},{"t":"Inequação com inversão de sinal","c":"−2x + 6 > 0 → −2x > −6 → x < 3 (inverteu ao dividir por −2)."},{"t":"Inequação do 2º grau","c":"x² − 4x + 3 < 0. Raízes: 1 e 3. Parábola com a > 0 é negativa ENTRE as raízes: S = (1, 3)."}],"exercicios":[{"q":"Resolva: 3(x − 2) + 5 = 2x + 7.","a":"3x − 6 + 5 = 2x + 7 → 3x − 1 = 2x + 7 → x = 8."},{"q":"Resolva: x² − 7x + 12 = 0.","a":"Δ = 49 − 48 = 1; x = (7±1)/2 → x = 4 ou x = 3."},{"q":"Resolva: 2x² + 3x − 2 = 0.","a":"Δ = 9 + 16 = 25; x = (−3±5)/4 → x = 1/2 ou x = −2."},{"q":"Para que valores de k a equação x² + kx + 9 = 0 tem raiz dupla?","a":"Δ = 0 → k² − 36 = 0 → k = ±6."},{"q":"Resolva a inequação: 5 − 3x ≥ 2x − 10.","a":"15 ≥ 5x → x ≤ 3. S = (−∞, 3]."},{"q":"Resolva: x² − 2x − 8 ≥ 0.","a":"Raízes: −2 e 4. a > 0 → positiva fora das raízes: S = (−∞, −2] ∪ [4, +∞)."},{"q":"Resolva: |2x − 4| = 10.","a":"2x − 4 = 10 → x = 7; ou 2x − 4 = −10 → x = −3."},{"q":"Resolva: |x − 3| < 5.","a":"−5 < x − 3 < 5 → −2 < x < 8. S = (−2, 8)."},{"q":"A soma de dois números é 12 e o produto é 32. Quais são?","a":"São raízes de t² − 12t + 32 = 0 → t = 4 ou t = 8."}]},{"id":"funcoes-afim","titulo":"4. Funções: conceito e função afim","semanas":"Semanas 8–10","teoria":["Uma função f: A → B associa cada elemento x de A (domínio) a exatamente um elemento f(x) de B. A imagem é o conjunto dos valores efetivamente atingidos. Este conceito é O mais importante do módulo: cálculo inteiro é o estudo de funções.","Domínio na prática: procure restrições. Denominador ≠ 0; radicando de raiz de índice par ≥ 0. Ex.: f(x) = 1/√(x − 2) exige x − 2 > 0, ou seja, D = (2, +∞).","Função afim: f(x) = ax + b. Gráfico é uma reta; a é o coeficiente angular (inclinação = taxa de variação) e b é onde a reta corta o eixo y. a > 0: crescente; a < 0: decrescente. Raiz (zero): x = −b/a.","Taxa de variação: a = (f(x₂) − f(x₁))/(x₂ − x₁). Guarde essa ideia — a derivada, lá no Cálculo Diferencial, é exatamente esse conceito levado ao limite.","Composição: (f ∘ g)(x) = f(g(x)). Função inversa f⁻¹ desfaz f: troque x por y e isole y."],"exemplos":[{"t":"Encontrando a lei da reta","c":"Reta passa por (1, 5) e (3, 11). a = (11−5)/(3−1) = 3. Com (1,5): 5 = 3·1 + b → b = 2. Logo f(x) = 3x + 2."},{"t":"Composição","c":"f(x) = 2x + 1, g(x) = x². (f∘g)(x) = f(x²) = 2x² + 1; (g∘f)(x) = (2x+1)² = 4x² + 4x + 1. Ordem importa!"},{"t":"Modelo linear real","c":"Corrida: bandeirada R$ 5 + R$ 2,50/km → C(d) = 5 + 2,5d. Custo de 8 km: C(8) = 25 reais."}],"exercicios":[{"q":"Determine o domínio de f(x) = √(x + 4)/(x − 1).","a":"x + 4 ≥ 0 e x ≠ 1 → D = [−4, 1) ∪ (1, +∞)."},{"q":"Se f(x) = 3x − 7, calcule f(0), f(2) e resolva f(x) = 8.","a":"f(0) = −7; f(2) = −1; 3x − 7 = 8 → x = 5."},{"q":"Encontre a função afim cujo gráfico passa por (0, 4) e (2, 10).","a":"a = (10−4)/2 = 3; b = 4. f(x) = 3x + 4."},{"q":"Um plano de streaming custa R$ 30 fixos + R$ 4 por conteúdo extra. Escreva a função custo e diga quantos extras cabem em R$ 70.","a":"C(n) = 30 + 4n; 30 + 4n ≤ 70 → n ≤ 10."},{"q":"f(x) = x + 3 e g(x) = 2x − 1. Calcule (f∘g)(2) e (g∘f)(2).","a":"(f∘g)(2) = f(3) = 6; (g∘f)(2) = g(5) = 9."},{"q":"Encontre a inversa de f(x) = (x − 4)/3.","a":"y = (x−4)/3 → x = 3y + 4 → f⁻¹(x) = 3x + 4."},{"q":"Para que valores de x a função f(x) = −2x + 8 é positiva?","a":"−2x + 8 > 0 → x < 4."},{"q":"Classifique f(x) = 5 − 3x como crescente ou decrescente e encontre sua raiz.","a":"a = −3 < 0: decrescente. Raiz: x = 5/3."}]},{"id":"quadratica","titulo":"5. Função quadrática","semanas":"Semanas 11–12","teoria":["f(x) = ax² + bx + c (a ≠ 0). Gráfico: parábola. a > 0: concavidade pra cima (tem mínimo); a < 0: pra baixo (tem máximo).","Vértice: xᵥ = −b/2a e yᵥ = −Δ/4a. O vértice é o ponto de máximo ou mínimo — problemas de otimização elementares vivem aqui.","Raízes cortam o eixo x (quando Δ ≥ 0); c corta o eixo y; o eixo de simetria é a reta x = xᵥ.","Forma fatorada: f(x) = a(x − x₁)(x − x₂). Forma canônica: f(x) = a(x − xᵥ)² + yᵥ — útil pra enxergar transformações do gráfico.","Estudo de sinal (revisão da aula 3, agora com olhar gráfico): sinal de a fora das raízes, sinal oposto entre elas."],"exemplos":[{"t":"Vértice e imagem","c":"f(x) = x² − 6x + 5. xᵥ = 6/2 = 3; yᵥ = f(3) = 9 − 18 + 5 = −4. Mínimo −4 → Im = [−4, +∞)."},{"t":"Otimização clássica","c":"Lucro L(x) = −2x² + 120x. Máximo em xᵥ = −120/(−4) = 30 unidades; L(30) = −1800 + 3600 = R$ 1800."}],"exercicios":[{"q":"Para f(x) = x² − 4x + 3, determine raízes, vértice e esboce o sinal.","a":"Raízes 1 e 3; vértice (2, −1); positiva fora de (1,3), negativa entre."},{"q":"Encontre o valor máximo de f(x) = −x² + 8x − 12.","a":"xᵥ = 4; f(4) = −16 + 32 − 12 = 4. Máximo = 4."},{"q":"Uma bola tem altura h(t) = −5t² + 20t (metros, segundos). Qual a altura máxima e quando ela ocorre?","a":"tᵥ = 2 s; h(2) = −20 + 40 = 20 m."},{"q":"Determine k para que f(x) = x² + 6x + k tenha imagem [−2, +∞).","a":"yᵥ = −2 → k − 9 = −2 → k = 7 (pois yᵥ = f(−3) = 9 − 18 + k)."},{"q":"Escreva f(x) = x² − 2x − 15 na forma fatorada.","a":"Raízes 5 e −3 → f(x) = (x − 5)(x + 3)."},{"q":"Com 40 m de cerca, qual o retângulo de maior área encostado num muro (só 3 lados cercados)?","a":"A(x) = x(40 − 2x) = −2x² + 40x. xᵥ = 10 → dimensões 10 × 20, área 200 m²."},{"q":"Determine a imagem de f(x) = 2x² − 4x + 7.","a":"xᵥ = 1; yᵥ = 2 − 4 + 7 = 5. a > 0 → Im = [5, +∞)."},{"q":"Resolva graficamente (estudo de sinal): −x² + 5x − 6 ≥ 0.","a":"Raízes 2 e 3; a < 0 → positiva entre as raízes: S = [2, 3]."}]},{"id":"exp-log","titulo":"6. Função exponencial e logaritmo","semanas":"Semanas 13–15","teoria":["Exponencial: f(x) = aˣ com a > 0, a ≠ 1. Se a > 1: crescente (crescimento exponencial); se 0 < a < 1: decrescente (decaimento). Domínio ℝ, imagem (0, +∞) — exponencial nunca zera nem fica negativa.","Equações exponenciais: iguale as bases. 2ˣ = 32 → 2ˣ = 2⁵ → x = 5. Quando não dá pra igualar bases, entra o logaritmo.","Logaritmo é o inverso da exponencial: log_a(b) = x ⟺ aˣ = b. Ex.: log₂ 8 = 3 porque 2³ = 8. Condições: a > 0, a ≠ 1, b > 0.","Propriedades (as três que resolvem 90% dos problemas): log(m·n) = log m + log n; log(m/n) = log m − log n; log(mᵏ) = k·log m. Mudança de base: log_a b = log b / log a.","Aplicações reais: juros compostos M = C(1+i)ᵗ, crescimento populacional, decaimento radioativo, escala Richter, pH, e — no seu mundo — complexidade O(log n) de algoritmos."],"exemplos":[{"t":"Equação exponencial","c":"3^(2x−1) = 27 → 3^(2x−1) = 3³ → 2x − 1 = 3 → x = 2."},{"t":"Tempo pra dobrar um investimento","c":"Quanto tempo pra dobrar a 10% a.a.? 2 = (1,1)ᵗ → t = log 2/log 1,1 ≈ 0,301/0,0414 ≈ 7,3 anos."},{"t":"Log com propriedades","c":"Se log 2 = 0,30 e log 3 = 0,48: log 12 = log(4·3) = 2·log 2 + log 3 = 0,60 + 0,48 = 1,08."}],"exercicios":[{"q":"Resolva: 2^(x+3) = 64.","a":"64 = 2⁶ → x + 3 = 6 → x = 3."},{"q":"Resolva: 5^(2x) = 1/125.","a":"1/125 = 5⁻³ → 2x = −3 → x = −3/2."},{"q":"Calcule: log₃ 81, log₅ (1/25) e log₁₀ 0,001.","a":"4; −2; −3."},{"q":"Se log 2 = 0,30, calcule log 8 e log 5.","a":"log 8 = 3·0,30 = 0,90; log 5 = log(10/2) = 1 − 0,30 = 0,70."},{"q":"Resolva: log₂(x − 1) = 3.","a":"x − 1 = 2³ = 8 → x = 9 (e 9 − 1 > 0 ✓)."},{"q":"Resolva: log(x) + log(x − 3) = 1 (base 10).","a":"log(x² − 3x) = 1 → x² − 3x = 10 → x = 5 ou x = −2; só x = 5 vale (domínio)."},{"q":"Um servidor dobra o volume de logs a cada ano. Hoje tem 4 TB. Em quantos anos passa de 100 TB?","a":"4·2ᵗ > 100 → 2ᵗ > 25 → t > log 25/log 2 ≈ 4,64 → 5 anos."},{"q":"Busca binária em uma lista ordenada de 1.000.000 itens faz no máximo quantas comparações? (⌈log₂ n⌉)","a":"log₂ 10⁶ ≈ 19,9 → 20 comparações."},{"q":"Resolva: 4ˣ − 6·2ˣ + 8 = 0. (Dica: y = 2ˣ)","a":"y² − 6y + 8 = 0 → y = 2 ou y = 4 → x = 1 ou x = 2."}]},{"id":"progressoes","titulo":"7. Progressões (PA e PG)","semanas":"Semanas 16–18","teoria":["Progressão Aritmética (PA): cada termo é o anterior somado de uma razão r constante. Termo geral: aₙ = a₁ + (n−1)r. Soma dos n primeiros: Sₙ = (a₁ + aₙ)·n/2.","Progressão Geométrica (PG): cada termo é o anterior multiplicado por uma razão q. Termo geral: aₙ = a₁·qⁿ⁻¹. Soma finita: Sₙ = a₁(qⁿ − 1)/(q − 1).","PG infinita com |q| < 1 converge: S = a₁/(1 − q). Primeira porta de entrada pro conceito de limite — vamos reencontrar isso em Sequências e Séries (etapa 6).","PA modela crescimento linear (juros simples, parcelas fixas); PG modela crescimento exponencial (juros compostos, viralização, replicação). Compare com as aulas 4 e 6: PA ↔ função afim, PG ↔ exponencial."],"exemplos":[{"t":"PA — termo geral","c":"PA: 5, 8, 11, ... r = 3. a₂₀ = 5 + 19·3 = 62."},{"t":"Soma de Gauss","c":"1 + 2 + ... + 100 = (1 + 100)·100/2 = 5050."},{"t":"PG infinita","c":"1 + 1/2 + 1/4 + ... = 1/(1 − 1/2) = 2."}],"exercicios":[{"q":"Na PA (7, 12, 17, ...), determine o 15º termo e a soma dos 15 primeiros.","a":"a₁₅ = 7 + 14·5 = 77; S₁₅ = (7+77)·15/2 = 630."},{"q":"Quantos múltiplos de 7 existem entre 100 e 500?","a":"Primeiro: 105, último: 497. 497 = 105 + (n−1)·7 → n = 57."},{"q":"Na PG (3, 6, 12, ...), calcule o 10º termo.","a":"a₁₀ = 3·2⁹ = 1536."},{"q":"Interpole 3 meios aritméticos entre 4 e 20.","a":"5 termos: 20 = 4 + 4r → r = 4. PA: 4, 8, 12, 16, 20."},{"q":"Calcule a soma da PG infinita 9 + 3 + 1 + 1/3 + ...","a":"q = 1/3; S = 9/(1 − 1/3) = 27/2 = 13,5."},{"q":"Uma dívida é paga em 12 parcelas em PA: a primeira de R$ 100 e a última de R$ 320. Qual o total pago?","a":"S = (100 + 320)·12/2 = R$ 2520."},{"q":"Um vírus de rede infecta 2 máquinas no minuto 1 e triplica a cada minuto. Quantas máquinas novas no minuto 8? E o total acumulado?","a":"a₈ = 2·3⁷ = 4374; S₈ = 2(3⁸−1)/2 = 6560."},{"q":"Escreva 0,777... como soma de PG infinita e obtenha a fração.","a":"0,7 + 0,07 + ... : a₁ = 7/10, q = 1/10 → S = (7/10)/(9/10) = 7/9."},{"q":"Numa PA, a₃ = 10 e a₇ = 26. Encontre a₁ e r.","a":"a₇ − a₃ = 4r = 16 → r = 4; a₁ = 10 − 2·4 = 2."}]}]}$j$::jsonb)
on conflict (id) do update set dados = excluded.dados;

insert into public.cursos (id, ordem, nome, sub, etiqueta, cor, cor_suave, curriculo)
values ('espanhol', 2, $s$Espanhol$s$, $s$Rumo ao DELE · A1 → B2 · 6 módulos$s$, $s$¡vamos!$s$, '#B23A2E', '#FDF1EE', $j$[{"etapa":"Nível A1","disciplinas":[{"id":"esp-a1-1","nome":"Espanhol Básico 1","ch":3,"ativo":true,"nota":"Sobrevivência: apresentar-se, ser/estar, números"},{"id":"esp-a1-2","nome":"Espanhol Básico 2","ch":3}]},{"etapa":"Nível A2","disciplinas":[{"id":"esp-a2-1","nome":"Pré-intermediário 1 — passado e rotina","ch":3},{"id":"esp-a2-2","nome":"Pré-intermediário 2 — futuro e opinião","ch":3}]},{"etapa":"Nível B1","disciplinas":[{"id":"esp-b1-1","nome":"Intermediário — subjuntivo e narração","ch":3}]},{"etapa":"Nível B2","disciplinas":[{"id":"esp-b2-1","nome":"Avançado — argumentação e nuance","ch":3}]}]$j$::jsonb)
on conflict (id) do update set ordem = excluded.ordem, nome = excluded.nome, sub = excluded.sub, etiqueta = excluded.etiqueta, cor = excluded.cor, cor_suave = excluded.cor_suave, curriculo = excluded.curriculo;

insert into public.modulos (id, curso_id, dados)
values ('esp-a1-1', 'espanhol', $j${"descricao":"O essencial pra começar a falar: se apresentar, ser/estar, artigos, números e horas. Atenção especial aos falsos amigos e às armadilhas do 'portunhol' — a proximidade com o português acelera, mas também engana. ~54h (3h/semana × 18 semanas).","livros":["Aula Internacional Plus 1 (A1) — Difusión. O livro-curso mais usado no mundo pra espanhol como língua estrangeira","Gramática de Uso del Español A1–B2 — Luis Aragonés & Ramón Palencia (SM). A referência de gramática com exercícios","Language Transfer — Complete Spanish (áudio, gratuito). Método excelente pra entender a lógica da língua","Español con Juan (podcast/YouTube, gratuito) — input compreensível desde o início","Meta de certificação: DELE A1 (Instituto Cervantes) ao fim dos dois módulos básicos"],"aulas":[{"id":"esp-saludos","titulo":"1. Saludos, apresentações e pronúncia","semanas":"Semanas 1–3","teoria":["Saudações básicas: hola (oi), buenos días (bom dia), buenas tardes (boa tarde), buenas noches (boa noite/boa noite ao chegar), ¿qué tal? / ¿cómo estás? (tudo bem?), hasta luego (até logo), adiós (tchau). Note os sinais invertidos ¿ e ¡ — em espanhol, pergunta e exclamação abrem e fecham.","Apresentar-se: Me llamo Eric (me chamo Eric), Soy de Brasil (sou do Brasil), Soy ingeniero (sou engenheiro), Tengo 40 años (tenho 40 anos — atenção: 'tener años', nunca 'ser'). Perguntas: ¿Cómo te llamas?, ¿De dónde eres?, ¿A qué te dedicas?","Pronomes pessoais: yo, tú, él/ella/usted, nosotros/nosotras, vosotros/vosotras, ellos/ellas/ustedes. Usted é o tratamento formal (conjuga na 3ª pessoa, como 'você' fazia no português antigo). Vosotros só se usa na Espanha; na América Latina, o plural é sempre ustedes.","Pronúncia — onde o brasileiro escorrega: J e G(e,i) têm som de RR forte (jamón, gente); LL e Y soam como 'dj/i' dependendo da região (llamar); Ñ = NH (mañana); RR é vibrante (perro ≠ pero); o V soa como B (vaca = 'baca'); e o E e O são sempre fechados — não existe 'é' aberto de 'café' paulistano.","Falsos amigos de primeira hora: embarazada = grávida (não 'envergonhada'); exquisito = delicioso; apellido = sobrenome; oficina = escritório; vaso = copo; largo = comprido; pelado = careca. Trate o portunhol como um dado sujo: parece certo, mas precisa validar."],"exemplos":[{"t":"Diálogo de apresentação","c":"— ¡Hola! ¿Cómo te llamas?  — Me llamo Eric, ¿y tú?  — Soy Lucía. ¿De dónde eres?  — Soy de Brasil, de São Paulo. ¿A qué te dedicas?  — Soy ingeniera de datos. ¡Mucho gusto!  — Encantado."},{"t":"Formal vs. informal","c":"Informal: ¿Cómo estás? ¿De dónde eres? — Formal (usted): ¿Cómo está? ¿De dónde es? A conjugação muda junto com o tratamento."},{"t":"Armadilha do portunhol","c":"'La oficina está cerca' = 'O escritório fica perto' — não é oficina mecânica (que em espanhol é 'taller')."}],"exercicios":[{"tipo":"card","f":"¿Cómo te llamas?","v":"Como você se chama? — Resposta: Me llamo…"},{"tipo":"card","f":"Mucho gusto / Encantado","v":"Muito prazer (encantado varia: encantada se quem fala é mulher)"},{"tipo":"card","f":"¿De dónde eres?","v":"De onde você é? — Soy de Brasil."},{"tipo":"card","f":"Hasta luego / Hasta mañana","v":"Até logo / Até amanhã"},{"tipo":"card","f":"embarazada","v":"grávida (falso amigo! 'envergonhada' = avergonzada)"},{"tipo":"mc","q":"Complete: ¿___ te dedicas?","op":["A qué","De qué","Por qué","Cuál"],"c":0,"e":"'¿A qué te dedicas?' = 'com o que você trabalha?'. A preposição 'a' vem do verbo dedicarse A algo."},{"tipo":"mc","q":"Qual é o plural de 'tú' usado na América Latina?","op":["vosotros","ustedes","vos","ellos"],"c":1,"e":"Vosotros só na Espanha. Na América Latina o plural informal e formal é ustedes."},{"tipo":"mc","q":"'Tengo 40 años' usa 'tener' porque em espanhol…","op":["idade é posse, nunca 'ser'","'ser' não existe","é regionalismo","tanto faz"],"c":0,"e":"Idade sempre com tener: tengo, tienes, tiene… años. 'Soy 40 años' é erro clássico de brasileiro."},{"q":"Traduza: 'Oi! Eu me chamo Eric, sou do Brasil e sou engenheiro de dados. Muito prazer!'","a":"¡Hola! Me llamo Eric, soy de Brasil y soy ingeniero de datos. ¡Mucho gusto!"}]},{"id":"esp-ser-estar","titulo":"2. Ser, estar e artigos","semanas":"Semanas 4–7","teoria":["SER (identidade, essência, origem, profissão, hora): soy, eres, es, somos, sois, son. Ex.: Soy brasileño. Es ingeniera. Son las tres (são três horas).","ESTAR (estado, localização, resultado): estoy, estás, está, estamos, estáis, están. Ex.: Estoy cansado. El libro está en la mesa. A regra prática é a mesma do português — a diferença é que o espanhol é mais rígido: localização é SEMPRE estar (¿Dónde está la estación?), inclusive de coisas fixas.","Pares que mudam de sentido: ser aburrido (ser chato) vs. estar aburrido (estar entediado); ser listo (ser esperto) vs. estar listo (estar pronto); ser rico (ser rico) vs. estar rico (estar gostoso, comida).","Artigos definidos: el, la, los, las. Indefinidos: un, una, unos, unas. Regra geral: -o masculino, -a feminino, mas há traições em relação ao português: el árbol (a árvore), la leche (o leite), la sangre (o sangue), el viaje (a viagem), la nariz (o nariz). Palavras em -aje são masculinas (el garaje); em -umbre, femininas (la costumbre).","Contrações: só existem DUAS: a + el = al, de + el = del. Nada de 'no', 'na', 'da' como no português — en la casa, de la empresa."],"exemplos":[{"t":"Ser × estar na prática","c":"Eric ES ingeniero (profissão → ser), pero hoy ESTÁ cansado (estado → estar). La oficina ESTÁ en el centro (localização → estar)."},{"t":"Gênero traiçoeiro","c":"'El equipo procesa la sangre de los datos' — brincadeira à parte: la sangre (fem.), el equipo (masc.), la leche (fem.). Decore o artigo junto com a palavra, como chave composta."},{"t":"Contração obrigatória","c":"Voy AL trabajo (a + el). Vengo DEL gimnasio (de + el). Mas: voy A LA oficina — 'a la' não contrai."}],"exercicios":[{"tipo":"mc","q":"Complete: La estación ___ cerca del hotel.","op":["es","está","son","estás"],"c":1,"e":"Localização é sempre ESTAR, mesmo de coisas fixas como uma estação."},{"tipo":"mc","q":"Complete: Nosotros ___ ingenieros.","op":["estamos","somos","es","están"],"c":1,"e":"Profissão/identidade → SER, 1ª pessoa do plural: somos."},{"tipo":"mc","q":"Qual frase significa 'a comida está gostosa'?","op":["La comida es rica","La comida está rica","La comida es lista","La comida está larga"],"c":1,"e":"Estar rico = estar gostoso (estado momentâneo). Ser rico = ter dinheiro."},{"tipo":"mc","q":"Escolha o artigo correto: ___ leche está fría.","op":["El","La","Lo","Un"],"c":1,"e":"La leche é feminino em espanhol — ao contrário do português 'o leite'."},{"tipo":"card","f":"el árbol / la sangre / el viaje / la nariz","v":"gêneros invertidos vs. português: a árvore / o sangue / a viagem / o nariz"},{"tipo":"card","f":"ser: soy, eres, es, somos, sois, son","v":"identidade, origem, profissão, hora"},{"tipo":"card","f":"estar: estoy, estás, está, estamos, estáis, están","v":"estado, localização, resultado"},{"q":"Traduza: 'O escritório fica no centro, perto do metrô.'","a":"La oficina está en el centro, cerca del metro. (oficina = escritório; de + el = del)"},{"q":"Corrija os erros: 'Yo estoy ingeniero y soy en la oficina ahora.'","a":"Yo SOY ingeniero (profissão → ser) y ESTOY en la oficina ahora (localização → estar)."}]},{"id":"esp-numeros","titulo":"3. Números, dias e horas","semanas":"Semanas 8–11","teoria":["0–15 são únicos: cero, uno, dos, tres, cuatro, cinco, seis, siete, ocho, nueve, diez, once, doce, trece, catorce, quince. De 16 a 29 escreve-se junto: dieciséis, diecisiete… veintiuno, veintidós… A partir de 31, separado com 'y': treinta y uno, cuarenta y dos.","Dezenas: diez, veinte, treinta, cuarenta, cincuenta, sesenta, setenta, ochenta, noventa. Centenas: cien (100 exato), ciento uno (101), doscientos, trescientos… quinientos (500, irregular!), setecientos, novecientos. Mil = mil; 1.000.000 = un millón.","Dias da semana (minúscula, masculinos): lunes, martes, miércoles, jueves, viernes, sábado, domingo. 'Na segunda' = el lunes; 'às segundas' = los lunes. Meses: enero, febrero, marzo, abril, mayo, junio, julio, agosto, septiembre, octubre, noviembre, diciembre.","Horas — sempre com SER e artigo feminino: Es la una (1h, singular!), Son las dos, Son las tres y media (3h30), Son las cuatro y cuarto (4h15), Son las cinco menos cuarto (4h45). ¿Qué hora es? pra perguntar.","Armadilhas: 'quinientos' (500) não é 'cincocientos'; sábado e domingo têm plural (los sábados) mas lunes–viernes não mudam (el lunes / los lunes)."],"exemplos":[{"t":"Preço e quantidade","c":"— ¿Cuánto cuesta? — Cuesta cuarenta y cinco euros con cincuenta (45,50 €)."},{"t":"Marcando reunião","c":"La reunión es el martes a las diez y media de la mañana. (dia com 'el', hora com 'a las')"},{"t":"Hora quebrada","c":"8h45 = Son las nueve menos cuarto (faltam 15 pras 9) — o espanhol clássico conta 'pra trás' depois da meia hora."}],"exercicios":[{"tipo":"card","f":"quince / cincuenta / quinientos","v":"15 / 50 / 500 (quinientos é irregular — não é 'cincocientos')"},{"tipo":"card","f":"lunes, martes, miércoles, jueves, viernes","v":"segunda, terça, quarta, quinta, sexta (minúscula, e não mudam no plural)"},{"tipo":"card","f":"Son las tres y media","v":"São 3h30 (hora sempre com ser + artigo feminino las; 1h = Es la una)"},{"tipo":"mc","q":"Como se escreve 76?","op":["setenta y seis","sesenta y seis","setecientos seis","siete y seis"],"c":0,"e":"70 = setenta (cuidado: 60 = sesenta). A partir de 31: dezena + y + unidade."},{"tipo":"mc","q":"'A reunião é na quinta às 9h15' →","op":["La reunión es el jueves a las nueve y cuarto","La reunión está en jueves a las nueve y quince","La reunión es en el jueves a nueve y cuarto","La reunión es el jueves en las nueve y media"],"c":0,"e":"Dia com 'el' (sem 'en'), hora com 'a las', 15 min = 'y cuarto'."},{"tipo":"mc","q":"1h da tarde em espanhol:","op":["Son las una","Es la una","Está la una","Son la una"],"c":1,"e":"Uma hora é singular: ES LA una. Das 2h em diante: SON LAS dos, tres…"},{"q":"Escreva por extenso: 348.","a":"Trescientos cuarenta y ocho."},{"q":"Traduza: 'Eu estudo espanhol às terças e quintas, das 20h às 21h30.'","a":"Estudio español los martes y los jueves, de (las) ocho a (las) nueve y media de la noche."},{"q":"Escreva por extenso em espanhol: 1.520 (mil quinhentos e vinte).","a":"Mil quinientos veinte."}]}]}$j$::jsonb)
on conflict (id) do update set dados = excluded.dados;

